#nullable enable // autogenerated

using MVZ2.GameContent.Contraptions;
using MVZ2.Vanilla.Detections;
using MVZ2.Vanilla.Enemies;
using MVZ2.Vanilla.Entities;
using PVZEngine.Collisions;
using PVZEngine.Entities;
using UnityEngine;

namespace MVZ2.GameContent.Detections
{
    public class StoneEyeDetector : Detector
    {
        public StoneEyeDetector(Vector3 shootOffset)
        {
            this.shootOffset = shootOffset;
        }
        protected override Bounds GetDetectionBounds(Entity self)
        {
            var offset = shootOffset;
            offset.x *= self.GetFacingX();
            var source = self.Position + shootOffset;

            var sizeX = StoneEye.GetRealRange(self);
            var sizeY = 48;
            var sizeZ = 48;
            var centerX = source.x + (sizeX * 0.5f * self.GetFacingX());
            var centerY = source.y;
            var centerZ = source.z;

            return new Bounds(new Vector3(centerX, centerY, centerZ), new Vector3(sizeX, sizeY, sizeZ));
        }
        protected override bool ValidateCollider(DetectionParams param, IEntityCollider collider)
        {
            if (!collider.IsForMain())
                return false;
            return base.ValidateCollider(param, collider);
        }
        public override bool ValidateTarget(DetectionParams self, Entity target)
        {
            if (target.ImmuneSlowing())
                return false;
            return base.ValidateTarget(self, target);
        }
        public Vector3 shootOffset;
    }
}
